var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OLD_NPC_CLAN_NULL","text":{"KOREA":"꽃 사세요, 꽃~","JPN":"花はいかがかね～","ENG":"Buy your bouquets and flowers!","TWN":"來買花喔～"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OLD_NPC_CLAN_NULL","text":{"KOREA":"아, 거기- 젊은 아가씨도 한 송이 받으시구랴.","JPN":"あっ、そこのお嬢ちゃんも一輪どうぞ。","ENG":"Young lady. Here. Have a flower.","TWN":"小姐～這束花送你。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"천리향이라… 화천에선 보기 드문 꽃이구려.","JPN":"瑞香か……華天では珍しい花ですね。","ENG":"Daphne... Not a common flower to see in Huatian.","TWN":"是月橘…這種花在華天很少見。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"OLD_NPC_CLAN_NULL","text":{"KOREA":"그래요. 전에는 이렇게 자주 피는 꽃이 아니었는데, 세상이 변해가고 있는 모양이지.","JPN":"そうじゃろ。もともとこんなによく咲く花じゃなかったのに、世の中が変わってきているようだね。","ENG":"Yes. It didn't bloom this frequently back then, but the world is changing.","TWN":"是啊，以前並不常看到這種花，看來世界正在發生變化。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"간만이오, 사저.","JPN":"ご無沙汰しております、師姉。","ENG":"Long time no see.","TWN":"師姐，好久不見。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"아, 사매구나.","JPN":"ああ、師妹か。","ENG":"Oh, you're here.","TWN":"喔，原來是師妹。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"같은 스승을 둔 제자끼리 이렇게 얼굴 마주보기도 쉽지 않네.","JPN":"同じ師匠の弟子同士でも、こうやって顔を合わせることが難しいとは。","ENG":"Why is it so hard to see each other when we have served the same master?","TWN":"我們雖然師出同門，但要見上一面也不容易呢。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"천리향은 흑동 문주의 죽음… 향을 피우러 오는 것이 도리이니 말이오.","JPN":"瑞香は黒東門主の喪失……お香を焚くために参るのが道理でございます。","ENG":"Daphne, the passing of Black East's sect leader... It is our duty to light an incense to pay our respects.","TWN":"月橘表示黑東掌門人的離世…理當來上香。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"여전히 쌀쌀맞은 반응이구나. 변함없이.","JPN":"相変わらず素っ気ないな。","ENG":"Cold, as usual, I see.","TWN":"你的反應都沒變呢，一樣冷淡。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"흑동의 사람은 사사로이 정을 두지 않소. 그것이 규칙이기에 따를 뿐.","JPN":"黒東の者は、私情を挟むことはありません。規則に従うだけです。","ENG":"Members of Black East care not about emotions. I am merely abiding by the rules.","TWN":"黑東的人不輕易表露情感，我只是遵守規則而已。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"사담은 이쯤 나누지. 장문인께서 너에게 물건을 남기셨어.","JPN":"雑談はここまでにしよう。掌門人が師妹にある物を残した。","ENG":"Enough small talk. The sect master has left you something.","TWN":"話家常就倒此為止，掌門人有東西要交給你。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이건…? 사부님의 무기구려.","JPN":"これは……？　師匠の武器ですか。","ENG":"This is... Master's weapon.","TWN":"這是…？師父的武器。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그래, 장문인께선 네가 흑동의 문주 자릴 이어받길 원하셨거든.","JPN":"そうだ、掌門人は師妹に黒東の門主を受け継いでもらいたかったのだ。","ENG":"Correct. The sect master wanted you to be the next sect leader.","TWN":"沒錯，掌門人希望由你來繼承黑東幫主的位置。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그러기 위해선, 전통에 따라 사매도 섭리음양의 시련을 치러야겠지.","JPN":"そのためには伝統に従い、師妹も燮理陰陽の試練を受けなければならないであろう。","ENG":"However, tradition dictates that you must first pass the trial of the balance of yin and yang.","TWN":"因此你也必須按照傳統，經過燮理陰陽的考試。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인은 창을 다룰 줄 모르오.","JPN":"自分は槍を扱えません。","ENG":"I do not know how to wield a spear.","TWN":"我不懂如何使用長槍。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"게다가 사부님의 자릴 이어받기 위한 전승 수업은 사저가 받지 않았소? ","JPN":"それに、師匠の跡を受け継ぐための伝承授業を受けているのも、自分ではありません。 ","ENG":"Also, was it not you who our master trained to be his successor?","TWN":"而且師姊不是一直有在接受訓練，預備要接師父的位置嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"뭐든 금방 배우는 게 네 체질이잖니. 문주의 역할이란 것도 차차 배워나가면 될 일이야.","JPN":"師妹は何でもすぐ覚えるでしょう？　門主の役割というものも、そのうち慣れていけばいいだけだ。","ENG":"Nonetheless, you are a quick study. You will learn how to assume the role of sect leader.","TWN":"你天生就學得快，一定也可以慢慢學會當幫主的。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"뭣보다… 장문인께서 마지막 순간 너를 다음 문주로 결정하신 것엔 그럴 만한 이유가 있지 않겠니?","JPN":"何より……掌門人が息を引き取る際、師妹を次の門主に決めたのには、それなりの理由があるはずではないか？","ENG":"Above all... there must be a good reason for him to choose you as his successor. Wouldn't you agree?","TWN":"最重要的是…掌門人在臨終前，選定你為下一任幫主，想必是有他的理由的。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…그렇다면 준비는 되었다오.","JPN":"……であれば、準備はできております。","ENG":"...Then, I am ready.","TWN":"…好吧，那我準備妥當。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"좋아. 그럼 시작해볼까?","JPN":"いいだろう、では始めよう。","ENG":"Very well. Let us start.","TWN":"好，那就開始吧？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"흑동의 새 문주는 백서의 문주를 결정할 의무가 있다.","JPN":"黒東の新しい門主は、白西の門主を決める義務がある。","ENG":"The new leader of Black East has a duty to appoint White West's leader.","TWN":"\\n黑東的新幫主有義務決定白西的幫主。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"섭리음양의 법칙에 따라 자신보다 뛰어나거나 대등한 백서 문파의 자제와 혼약을 치러 부부의 연을 맺는 것이다.","JPN":"燮理陰陽のルールに従い自分より優れている者、または対等な白西門派の子弟と婚約を結び夫婦になるのだ。","ENG":"According to the laws of the balance of yin and yang, you must wed a disciple of White West who is equal to or stronger than yourself.","TWN":"\\n根據燮理陰陽的規定，新幫主必須在白西門派中，找到比自己優秀或地位相當的弟子訂親。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"기한은 삼 년. 그 안에 약혼자를 찾지 못하면 사매의 문주 권한은 박탈돼.","JPN":"3年以内に婚約者を探し出せなければ、師妹の門主権限は剥奪される。","ENG":"Three years. If you do not find a fiancé within three years, your candidacy as sect leader will be withdrawn.","TWN":"期限是三年，若是三年內找不到合適人選，將會取消你幫主的資格。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"백서 문파의 자제들은 각자 수행을 위해 속세에 녹아 들어 지낸다고 들었소만…","JPN":"白西門派の子弟は、修行のために俗世間に紛れ込んで暮らしていると聞いておりますが……","ENG":"I heard the disciples of White West live assimilated in the real world for their practice...","TWN":"但我聽說白西門派的弟子，都散落在俗世中修行…"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"어떻게 하면 그들을 만날 수 있는 것이오?","JPN":"どうしたら彼らに会えるのですか？","ENG":"How am I to meet any of them?","TWN":"要如何才能找到他們？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"흑동의 문주에게 주어지는 무기 막야는 본래 간장이라는 백서의 보물과 한 쌍이다.","JPN":"黒東の門主に与えられる武器の莫耶は、本来干将という白西の宝物と一対になっている。","ENG":"Bakuya, the weapon given to the leader of Black East, and Kanshou, the treasure of White West, were originally a pair.","TWN":"黑東幫主的武器莫耶，原本和白西的寶物干將是一對的。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그리고 문주의 자격을 갖춘 백서의 자제들은 모두가 간장의 검조각을 몸에 지니고 있지.","JPN":"そして門主の資格を得た白西の子弟は、全員干将の剣の欠片を身につけている。","ENG":"Furthermore, all candidates to be the leader of White West carry a shard of Kanshou with them.","TWN":"而且具備幫主資格的白西弟子，身上都會隨身帶著干將的碎片。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"간장과 막야는 본래 한 쌍의 존재이니 서로가 나침반처럼 이끌릴 거야.","JPN":"干将と莫耶は元々一対の存在であり、互いが羅針盤のように引かれあうはずだ。","ENG":"As they were meant to be together, both Kanshou and Bakuya will pull each other closer.","TWN":"干將和莫耶本來就是一對，它們會像指南針一樣彼此吸引。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"보통은, 네가 찾기 전에 도전자들이 스스로 널 먼저 만나러 오겠지만?","JPN":"本来なら、師妹が探しだす前に挑戦者自らが会いに来るだろうが。","ENG":"However, they'll normally approach you first to challenge you before you find them.","TWN":"通常會是在你找到他們之前，他們就會先找上你。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이해했소.","JPN":"理解いたしました。","ENG":"Understood.","TWN":"明白。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"다른 궁금한 게 있니?","JPN":"他に聞きたいことはあるか？","ENG":"Anything else you're curious about?","TWN":"還有其他問題嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"사부님의 마지막은… 어떠셨소?","JPN":"師匠の最期は……どうだったのでしょうか？","ENG":"How was our master's... last moment?","TWN":"師父臨終前……還好嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"모두가 지켜보는 가운데, 침상에서 평온하게 눈을 감으셨어.","JPN":"みんなが見守っている中、安らかにお亡くなりになった。","ENG":"He passed away peacefully in his sleep, with everyone watching over him.","TWN":"師父在眾人的陪伴下，安詳地闔上眼離開人世間。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…그렇구려.","JPN":"……然様でございますか。","ENG":"...I see.","TWN":"…原來如此。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그럼 다녀오리다.","JPN":"それでは、行って参ります。","ENG":"Then, it is time I left.","TWN":"那我出發了。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그래, 앞으로의 네 여정에 무운을 비마.","JPN":"師妹の旅にご武運あらんことを。","ENG":"Very well. I wish you the best of luck on your journey.","TWN":"好，祝你順利！"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"의외로군요.","JPN":"意外ですね。","ENG":"Who would've thought...","TWN":"真是意外。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"소식으로만 접했던 무시무시한 혈귀의 정체가 괴력의 거인이 아니라, 평범한 소녀였을 줄이야.","JPN":"噂でしか耳にしたことのない恐ろしい血鬼の正体が、怪力の巨人ではなく普通の少女であったとは。","ENG":"That the identity of the rumored ferocious Bloodseeker isn't some monstrous giant but an ordinary-looking girl.","TWN":"我還以為傳聞中可怕的血鬼會像浩克一樣，結果只是一名普通少女。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"뭐, 보고서만 보면 그런 오해를 살 만도 하지.","JPN":"まあ、報告書だけを見るとそう誤解するだろう。","ENG":"Well, just reading about her on paper would confuse anyone.","TWN":"嗯嗯，只看報告的話確實很容易誤會。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"현역시절의 사매는 암살이랍시고 현장을 죄 박살내고 다녔으니.","JPN":"現役時代の師妹は、暗殺任務につくと現場まで木端微塵にしていたから。","ENG":"When our junior disciple was still active, she would destroy the whole area and call it an assassination.","TWN":"因為師妹以前在當刺客時，常常把現場搞得天翻地覆的。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"아직 나이도 어려 보이는데 괜찮을까요?","JPN":"まだ幼いようですが、大丈夫でしょうか？","ENG":"She looks so young. Are you sure she'll be all right?","TWN":"她還那麼年輕，沒問題嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"대결에서 이기기 위해 백서의 도전자 측은 어떤 수단과 방법도 가릴 필요가 없다고 들었습니다만.","JPN":"白西の挑戦者は対決で勝つためには手段を選ばないと聞きましたが。","ENG":"I heard the challengers of White West could use any means necessary to defeat her.","TWN":"我聽說白西的挑戰者在決鬥中可以不擇手段，只求獲勝。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그런 불합리한 시험을 견뎌내는 것이 흑동 문주로서의 자격을 증명하는 길이다.","JPN":"そういう不合理な試練に耐えてみせることこそ、黒東の門主としての資格を証明することになる。","ENG":"Overcoming such an unreasonable trial is the only path to prove one's worth as the leader of Black East.","TWN":"就是要經過這種不合理的考驗，才能證明自己有資格成為黑東的幫主。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그리고 걱정마. 사매는 암살에 재능이 없을 뿐. 싸움은 누구보다 타고났으니까.","JPN":"それに暗殺の才能がないだけで、誰よりも喧嘩は強い。心配には及ばない。","ENG":"There is no need to worry about her. She may lack the talent to become an assassin, but she possesses natural fighting skills.","TWN":"而且不用擔心，師妹只是沒有當刺客的天分，但她在作戰能力方面是很出色的。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"난 오히려 사매가 삼 년 동안 마땅한 반려를 찾지 못할까 걱정이구나.","JPN":"私はむしろ、3年の間に最適な伴侶を探し出せないかもしれないという方が心配だ。","ENG":"I am more worried about her not being able to find a suitable life partner within three years.","TWN":"我比較擔心的是她在三年內找不到合適的伴侶。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};